def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
  import scala.collection.mutable
  import scala.util.control.Breaks._

  val n = nums.length
  val posMap = mutable.HashMap[Long, List[Int]]()

  // Preprocess: For each number, store the positions
  for (i <- 0 until n) {
    val num = nums(i)
    if (!posMap.contains(num)) {
      posMap(num) = List()
    }
    posMap(num) = i :: posMap(num)
  }

  val ans = mutable.ArrayBuffer[Long]()

  for (query <- queries) {
    val l = query(0).toInt
    val r = query(1).toInt
    val threshold = query(2).toInt
    val freq = mutable.HashMap[Long, Int]()

    var found = false
    var result = -1L

    // Check each number's positions
    for ((num, positions) <- posMap) {
      val left = positions.indexOf(l)
      val right = positions.indexOf(r)
      var count = 0

      // Use binary search to find the count in [l, r]
      val leftIdx = positions.indices.find(_ >= l).getOrElse(0)
      val rightIdx = positions.indices.find(_ > r).getOrElse(0)
      count = rightIdx - leftIdx

      if (count >= threshold) {
        freq(num) = count
        found = true
      }
